package fizeau

import (
	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/modelcatalog"
	"github.com/easel/fizeau/internal/routing"
)

func harnessPaymentKind(name string, cfg harnesses.HarnessConfig) BillingModel {
	if name == "" {
		name = cfg.Name
	}
	if billing := modelcatalog.BillingForHarness(name); billing != modelcatalog.BillingModelUnknown {
		return billing
	}
	if billing := modelcatalog.BillingForProviderSystem(name); billing != modelcatalog.BillingModelUnknown {
		return billing
	}
	if cfg.IsSubscription {
		return modelcatalog.BillingModelSubscription
	}
	if cfg.IsLocal {
		return modelcatalog.BillingModelFixed
	}
	return modelcatalog.BillingModelUnknown
}

func harnessRunsInProcessOrHTTP(cfg harnesses.HarnessConfig) bool {
	return cfg.IsHTTPProvider || cfg.IsLocal
}

func serviceProviderBilling(entry ServiceProviderEntry) BillingModel {
	if entry.Billing != modelcatalog.BillingModelUnknown {
		return entry.Billing
	}
	if billing := modelcatalog.BillingForProviderSystem(entry.Type); billing != modelcatalog.BillingModelUnknown {
		return billing
	}
	return modelcatalog.BillingForHarness(entry.Type)
}

func serviceProviderDefaultInclusion(entry ServiceProviderEntry) bool {
	if entry.IncludeByDefaultSet {
		return entry.IncludeByDefault
	}
	switch serviceProviderBilling(entry) {
	case modelcatalog.BillingModelFixed, modelcatalog.BillingModelSubscription:
		return true
	default:
		return false
	}
}

func providerTypeUsesFixedBilling(providerType string) bool {
	return modelcatalog.BillingForProviderSystem(providerType) == modelcatalog.BillingModelFixed
}

func routingHarnessEntryFromMetadata(name string, cfg harnesses.HarnessConfig, st harnesses.HarnessStatus) routing.HarnessEntry {
	billing := harnessPaymentKind(name, cfg)
	return routing.HarnessEntry{
		Name:                name,
		Surface:             cfg.Surface,
		CostClass:           cfg.CostClass,
		IsLocal:             billing == modelcatalog.BillingModelFixed,
		IsSubscription:      billing == modelcatalog.BillingModelSubscription,
		IsHTTPProvider:      cfg.IsHTTPProvider,
		AutoRoutingEligible: cfg.AutoRoutingEligible,
		TestOnly:            cfg.TestOnly,
		ExactPinSupport:     cfg.ExactPinSupport,
		DefaultModel:        cfg.DefaultModel,
		SupportedModels:     subprocessHarnessModelIDs(name, cfg),
		AutoRoutingModels:   subprocessHarnessAutoRoutingModels(name, cfg),
		SupportedReasoning:  supportedReasoning(cfg),
		MaxReasoningTokens:  cfg.MaxReasoningTokens,
		SupportedPerms:      supportedPermissions(cfg),
		SupportsTools:       true,
		Available:           st.Available,
		QuotaOK:             true,
		QuotaTrend:          routing.QuotaTrendUnknown,
		SubscriptionOK:      true,
	}
}

func routingHarnessUsesAccountBilling(entry *routing.HarnessEntry) bool {
	return entry != nil && entry.IsSubscription
}
package fizeau

import (
	"errors"
	"fmt"
	"strings"
	"time"
)

var (
	errHarnessModelIncompatible     = errors.New("agent: harness model incompatible")
	errPolicyRequirementUnsatisfied = errors.New("agent: policy requirement unsatisfied")
	errModelConstraintAmbiguous     = errors.New("agent: model constraint ambiguous")
	errModelConstraintNoMatch       = errors.New("agent: model constraint no match")
	errUnknownPolicy                = errors.New("agent: unknown policy")
	errUnsatisfiablePin             = errors.New("agent: unsatisfiable pin")
	errNoLiveProvider               = errors.New("agent: no live provider")
	errUnknownProvider              = errors.New("agent: unknown provider")
	errNoViableProviderForNow       = errors.New("agent: no viable provider for now")
)

// ErrUnknownProvider reports an explicit Provider pin that is not present in
// the service configuration. This is a pre-dispatch pin failure: the caller
// asked for a provider name that the service has no record of, so no route
// can be constructed.
type ErrUnknownProvider struct {
	// Provider is the provider name supplied by the caller.
	Provider string
	// KnownProviders is the set of provider names the service knows about
	// (empty when no ServiceConfig is configured).
	KnownProviders []string
}

func (e ErrUnknownProvider) Error() string {
	if len(e.KnownProviders) == 0 {
		return fmt.Sprintf("unknown provider %q", e.Provider)
	}
	return fmt.Sprintf("unknown provider %q; known providers: %s", e.Provider, strings.Join(e.KnownProviders, ", "))
}

func (e ErrUnknownProvider) Is(target error) bool {
	switch target.(type) {
	case ErrUnknownProvider, *ErrUnknownProvider:
		return true
	default:
		return errors.Is(errUnknownProvider, target)
	}
}

func (e ErrUnknownProvider) Unwrap() error {
	return errUnknownProvider
}

// ErrModelConstraintAmbiguous reports that an explicit Model pin matched more
// than one concrete model after normalization.
type ErrModelConstraintAmbiguous struct {
	// Model is the raw model pin supplied by the caller.
	Model string
	// Candidates are the concrete model IDs that matched the pin.
	Candidates []string
}

func (e ErrModelConstraintAmbiguous) Error() string {
	if len(e.Candidates) == 0 {
		return fmt.Sprintf("ambiguous model %q", e.Model)
	}
	return fmt.Sprintf("ambiguous model %q: candidates: %s", e.Model, strings.Join(e.Candidates, ", "))
}

func (e ErrModelConstraintAmbiguous) Is(target error) bool {
	switch target.(type) {
	case ErrModelConstraintAmbiguous, *ErrModelConstraintAmbiguous:
		return true
	default:
		return errors.Is(errModelConstraintAmbiguous, target)
	}
}

func (e ErrModelConstraintAmbiguous) Unwrap() error {
	return errModelConstraintAmbiguous
}

// ErrModelConstraintNoMatch reports that an explicit Model pin matched no
// discovered or catalog-resolved concrete model IDs.
type ErrModelConstraintNoMatch struct {
	// Model is the raw model pin supplied by the caller.
	Model string
	// Candidates are the nearby candidate IDs considered during resolution.
	Candidates []string
}

func (e ErrModelConstraintNoMatch) Error() string {
	if len(e.Candidates) == 0 {
		return fmt.Sprintf("no matching model for %q", e.Model)
	}
	return fmt.Sprintf("no matching model for %q; nearby candidates: %s", e.Model, strings.Join(e.Candidates, ", "))
}

func (e ErrModelConstraintNoMatch) Is(target error) bool {
	switch target.(type) {
	case ErrModelConstraintNoMatch, *ErrModelConstraintNoMatch:
		return true
	default:
		return errors.Is(errModelConstraintNoMatch, target)
	}
}

func (e ErrModelConstraintNoMatch) Unwrap() error {
	return errModelConstraintNoMatch
}

// DecisionWithCandidates is implemented by routing errors that retain the
// evaluated candidate trace for a failed ResolveRoute call.
type DecisionWithCandidates interface {
	error
	// RouteCandidates returns the evaluated candidates that led to the error.
	RouteCandidates() []RouteCandidate
}

type routeDecisionError struct {
	err        error
	candidates []RouteCandidate
}

func (e *routeDecisionError) Error() string {
	return e.err.Error()
}

func (e *routeDecisionError) Unwrap() error {
	return e.err
}

func (e *routeDecisionError) RouteCandidates() []RouteCandidate {
	return append([]RouteCandidate(nil), e.candidates...)
}

// ErrHarnessModelIncompatible reports an explicit Harness+Model pin that the
// harness allow-list cannot serve.
//
// DDx preflight callers should use errors.As to extract Harness, Model, and
// SupportedModels for worker logs or bead failure records. errors.Is matches a
// zero-value ErrHarnessModelIncompatible, even after callers wrap the error with
// fmt.Errorf and %w.
type ErrHarnessModelIncompatible struct {
	// Harness is the canonical harness name supplied by the caller.
	Harness string
	// Model is the exact concrete model pin supplied by the caller.
	Model string
	// SupportedModels is the harness allow-list that rejected Model.
	SupportedModels []string
}

func (e ErrHarnessModelIncompatible) Error() string {
	return fmt.Sprintf("model %q is not supported by harness %q; supported models: %s", e.Model, e.Harness, strings.Join(e.SupportedModels, ", "))
}

func (e ErrHarnessModelIncompatible) Is(target error) bool {
	switch target.(type) {
	case ErrHarnessModelIncompatible, *ErrHarnessModelIncompatible:
		return true
	default:
		return errors.Is(errHarnessModelIncompatible, target)
	}
}

func (e ErrHarnessModelIncompatible) Unwrap() error {
	return errHarnessModelIncompatible
}

// ErrPolicyRequirementUnsatisfied reports a hard policy requirement that no
// candidate, or an explicit caller pin, can satisfy.
type ErrPolicyRequirementUnsatisfied struct {
	Policy       string
	Requirement  string
	AttemptedPin string
	Rejected     int
}

func (e ErrPolicyRequirementUnsatisfied) Error() string {
	if e.AttemptedPin != "" {
		return fmt.Sprintf("policy %q requires %s but conflicts with %s", e.Policy, e.Requirement, e.AttemptedPin)
	}
	return fmt.Sprintf("policy %q has no candidate satisfying %s: %d candidates rejected", e.Policy, e.Requirement, e.Rejected)
}

func (e ErrPolicyRequirementUnsatisfied) Is(target error) bool {
	switch target.(type) {
	case ErrPolicyRequirementUnsatisfied, *ErrPolicyRequirementUnsatisfied:
		return true
	default:
		return errors.Is(errPolicyRequirementUnsatisfied, target)
	}
}

func (e ErrPolicyRequirementUnsatisfied) Unwrap() error {
	return errPolicyRequirementUnsatisfied
}

// ErrUnknownPolicy reports an explicit policy name that is not present in the
// model catalog.
type ErrUnknownPolicy struct {
	Policy string
}

func (e ErrUnknownPolicy) Error() string {
	return fmt.Sprintf("unknown routing policy %q", e.Policy)
}

func (e ErrUnknownPolicy) Is(target error) bool {
	switch target.(type) {
	case ErrUnknownPolicy, *ErrUnknownPolicy:
		return true
	default:
		return errors.Is(errUnknownPolicy, target)
	}
}

func (e ErrUnknownPolicy) Unwrap() error {
	return errUnknownPolicy
}
package fizeau

import (
	"fmt"
	"strings"
)

// Reserved cross-tool metadata keys (CONTRACT-003 § ExecuteRequest.Metadata).
// When the caller also sets one of these top-level fields and the same key
// in Metadata, the top-level field wins and a MetadataKeyCollision warning
// is emitted on the final event.
const (
	MetadataKeyRole          = "role"
	MetadataKeyCorrelationID = "correlation_id"
)

// MetadataWarningCodeKeyCollision is the ServiceFinalWarning.Code stamped
// onto the final event when caller-supplied Metadata duplicates a reserved
// top-level field (Role or CorrelationID).
const MetadataWarningCodeKeyCollision = "metadata_key_collision"

// Role normalization bounds (CONTRACT-003).
const roleMaxLen = 64

// CorrelationID normalization bounds (CONTRACT-003).
const correlationIDMaxLen = 256

// RoleNormalizationError is returned pre-dispatch when ServiceExecuteRequest.Role
// or RouteRequest.Role fails normalization (lowercased, alphanumeric+hyphen
// only, max 64 chars).
type RoleNormalizationError struct {
	// Role is the value that failed normalization.
	Role string
	// Reason is a short human-readable reason (e.g. "too long",
	// "contains invalid character").
	Reason string
}

func (e *RoleNormalizationError) Error() string {
	return fmt.Sprintf("invalid Role %q: %s", e.Role, e.Reason)
}

// CorrelationIDNormalizationError is returned pre-dispatch when
// ServiceExecuteRequest.CorrelationID or RouteRequest.CorrelationID fails
// normalization (printable ASCII, no whitespace except hyphen/colon/underscore,
// max 256 chars).
type CorrelationIDNormalizationError struct {
	CorrelationID string
	Reason        string
}

func (e *CorrelationIDNormalizationError) Error() string {
	return fmt.Sprintf("invalid CorrelationID %q: %s", e.CorrelationID, e.Reason)
}

// ValidateRole returns nil when role is empty (unset) or already
// normalized, and a typed *RoleNormalizationError otherwise. The empty
// string is treated as "unset". Callers should use the value as-is when
// validation succeeds — normalization here is identity-or-reject (we do
// not silently rewrite caller input).
func ValidateRole(role string) error {
	if role == "" {
		return nil
	}
	if len(role) > roleMaxLen {
		return &RoleNormalizationError{
			Role:   role,
			Reason: fmt.Sprintf("length %d exceeds max %d", len(role), roleMaxLen),
		}
	}
	for i := 0; i < len(role); i++ {
		c := role[i]
		switch {
		case c >= 'a' && c <= 'z':
		case c >= '0' && c <= '9':
		case c == '-':
		default:
			return &RoleNormalizationError{
				Role:   role,
				Reason: fmt.Sprintf("character %q at offset %d is not lowercase alphanumeric or hyphen", string(c), i),
			}
		}
	}
	return nil
}

// ValidateCorrelationID returns nil when id is empty or normalized, and a
// typed *CorrelationIDNormalizationError otherwise.
func ValidateCorrelationID(id string) error {
	if id == "" {
		return nil
	}
	if len(id) > correlationIDMaxLen {
		return &CorrelationIDNormalizationError{
			CorrelationID: id,
			Reason:        fmt.Sprintf("length %d exceeds max %d", len(id), correlationIDMaxLen),
		}
	}
	for i := 0; i < len(id); i++ {
		c := id[i]
		switch {
		case c >= 0x21 && c <= 0x7E && c != ' ':
			// printable ASCII; whitespace already excluded by 0x21 lower bound.
			// allow hyphen/colon/underscore implicitly along with the rest of
			// the printable range. Only reject if outside the printable range.
		default:
			return &CorrelationIDNormalizationError{
				CorrelationID: id,
				Reason:        fmt.Sprintf("byte 0x%02x at offset %d is not printable ASCII (no control chars or whitespace)", c, i),
			}
		}
	}
	return nil
}

// metaWithRoleAndCorrelation overlays the caller-supplied top-level Role
// and CorrelationID onto a copy of meta under the reserved metadata keys,
// per CONTRACT-003. Top-level wins on collision; existing meta entries
// for unrelated keys are preserved. Returns meta unchanged when both
// fields are empty (avoids unnecessary allocation).
func metaWithRoleAndCorrelation(meta map[string]string, role, correlationID string) map[string]string {
	if role == "" && correlationID == "" {
		return meta
	}
	out := make(map[string]string, len(meta)+2)
	for k, v := range meta {
		out[k] = v
	}
	if role != "" {
		out[MetadataKeyRole] = role
	}
	if correlationID != "" {
		out[MetadataKeyCorrelationID] = correlationID
	}
	return out
}

// metadataReservedKeyCollisions returns the reserved metadata keys whose
// caller-supplied Metadata value would be overridden by a non-empty
// top-level Role or CorrelationID. Used to emit the MetadataKeyCollision
// warning on the final event.
func metadataReservedKeyCollisions(meta map[string]string, role, correlationID string) []string {
	var out []string
	if role != "" {
		if v, ok := meta[MetadataKeyRole]; ok && v != "" && v != role {
			out = append(out, MetadataKeyRole)
		}
	}
	if correlationID != "" {
		if v, ok := meta[MetadataKeyCorrelationID]; ok && v != "" && v != correlationID {
			out = append(out, MetadataKeyCorrelationID)
		}
	}
	return out
}

// metadataKeyCollisionMessage formats a human-readable message for the
// MetadataKeyCollision warning surfaced on the final event.
func metadataKeyCollisionMessage(keys []string) string {
	if len(keys) == 0 {
		return ""
	}
	return fmt.Sprintf("top-level field(s) %s overrode caller Metadata entries with the same reserved key", strings.Join(keys, ", "))
}
package fizeau

import (
	"time"

	"github.com/easel/fizeau/internal/quota"
)

// ProviderQuotaState is the state of one provider in the quota state machine.
type ProviderQuotaState string

const (
	// ProviderQuotaStateAvailable means the provider has no known quota
	// exhaustion and is eligible for routing.
	ProviderQuotaStateAvailable ProviderQuotaState = "available"
	// ProviderQuotaStateQuotaExhausted means the provider returned a quota
	// signal (e.g. a 429 with Retry-After) and should be excluded from
	// routing until RetryAfter has elapsed.
	ProviderQuotaStateQuotaExhausted ProviderQuotaState = "quota_exhausted"
)

// ProviderQuotaStateStore is the per-provider quota state machine.
//
// Transitions:
//
//	available --MarkQuotaExhausted--> quota_exhausted
//	quota_exhausted --MarkAvailable--> available
//	quota_exhausted --(time passes RetryAfter)--> available
//
// The store is safe for concurrent use.
type ProviderQuotaStateStore struct {
	inner *quota.StateStore
}

// NewProviderQuotaStateStore returns an empty store. Every provider is
// implicitly available until MarkQuotaExhausted is called.
func NewProviderQuotaStateStore() *ProviderQuotaStateStore {
	return &ProviderQuotaStateStore{inner: quota.NewStateStore()}
}

// MarkQuotaExhausted transitions provider into quota_exhausted with the given
// retry_after. A zero or past retryAfter is normalized to "available" since
// there is no future window to exclude.
func (s *ProviderQuotaStateStore) MarkQuotaExhausted(provider string, retryAfter time.Time) {
	s.innerStore().MarkQuotaExhausted(provider, retryAfter)
}

// MarkAvailable forces provider back to available, dropping any pending
// retry_after. Use when an explicit recovery signal arrives (probe success,
// fresh quota window, operator override).
func (s *ProviderQuotaStateStore) MarkAvailable(provider string) {
	s.innerStore().MarkAvailable(provider)
}

// State returns the effective state of provider at the given instant. The
// quota_exhausted state auto-decays to available once now >= retry_after.
func (s *ProviderQuotaStateStore) State(provider string, now time.Time) (ProviderQuotaState, time.Time) {
	state, retryAfter := s.innerStore().State(provider, now)
	return ProviderQuotaState(state), retryAfter
}

// AllExhausted returns provider→retry_after for every provider whose entry is
// currently in quota_exhausted state, regardless of whether retry_after has
// elapsed. Unlike ExhaustedAt, entries past their retry_after are still
// reported here; the recovery probe loop uses this to find providers that are
// due for re-probing before the auto-decay in State() reveals them as
// available.
func (s *ProviderQuotaStateStore) AllExhausted() map[string]time.Time {
	return s.innerStore().AllExhausted()
}

// ExhaustedAt returns provider→retry_after for every provider currently in
// quota_exhausted state with retry_after > now. The returned map is a copy
// safe for the caller to mutate.
func (s *ProviderQuotaStateStore) ExhaustedAt(now time.Time) map[string]time.Time {
	return s.innerStore().ExhaustedAt(now)
}

func (s *ProviderQuotaStateStore) innerStore() *quota.StateStore {
	if s == nil {
		return nil
	}
	return s.inner
}
package fizeau

import (
	"time"

	"github.com/easel/fizeau/internal/quota"
)

// ProviderBurnRateTracker maintains a per-provider rolling window of token
// usage and compares observed burn-rate against an operator-configured daily
// token budget. When the projected end-of-window usage exceeds the budget,
// Record signals predictive exhaustion so the caller can pre-emptively
// transition the provider into quota_exhausted (without waiting for the
// real provider quota error).
//
// Window semantics (default):
//   - One window = one calendar day in UTC, starting at 00:00 UTC.
//   - When now crosses into the next UTC day, the prior window's usage is
//     dropped and counting starts fresh against the same daily budget.
//   - retry_after on a predicted-exhaustion transition is the start of the
//     NEXT UTC daily window (i.e. windowStart + 24h).
//
// Providers without a configured budget are inert: Record still tallies
// observed tokens (so the same tracker can report usage later) but never
// returns an exhausted=true signal.
//
// The tracker is safe for concurrent use.
type ProviderBurnRateTracker struct {
	inner *quota.BurnRateTracker
}

// NewProviderBurnRateTracker returns an empty tracker with no configured
// budgets.
func NewProviderBurnRateTracker() *ProviderBurnRateTracker {
	return &ProviderBurnRateTracker{inner: quota.NewBurnRateTracker()}
}

// SetBudget installs (or replaces) the daily token budget for provider.
// budget <= 0 disables predictive exhaustion for that provider (and removes
// any prior budget).
func (t *ProviderBurnRateTracker) SetBudget(provider string, budget int) {
	t.innerTracker().SetBudget(provider, budget)
}

// Budget returns the currently-configured daily budget for provider, or 0
// when none is set.
func (t *ProviderBurnRateTracker) Budget(provider string) int {
	return t.innerTracker().Budget(provider)
}

// Used returns the tokens recorded for provider in the current window at
// instant now. Crossing a window boundary resets the count to zero; the
// returned value reflects that reset.
func (t *ProviderBurnRateTracker) Used(provider string, now time.Time) int {
	return t.innerTracker().Used(provider, now)
}

// Record adds tokens to provider's rolling-window usage at instant now and
// evaluates whether predictive exhaustion has been triggered.
//
// Predictive rule (matches AC fizeau-f2661619 §3):
//
//	burn_rate        = used / elapsed
//	predicted_more   = burn_rate * remaining_window
//	exhausted        = predicted_more > (budget - used)
//
// In the equivalent "predicted total at window end > budget" form:
//
//	predicted_total  = used * (window_total / elapsed)
//
// If used >= budget already, exhausted is true with no projection needed.
//
// When exhausted, retryAfter is set to the start of the next daily window
// (windowStart + 24h, UTC). Otherwise the zero time.
//
// Providers with no configured budget always return exhausted=false.
func (t *ProviderBurnRateTracker) Record(provider string, tokens int, now time.Time) (exhausted bool, retryAfter time.Time) {
	return t.innerTracker().Record(provider, tokens, now)
}

// Reset drops all per-provider windows (budgets are preserved). Primarily
// useful in tests.
func (t *ProviderBurnRateTracker) Reset() {
	t.innerTracker().Reset()
}

// observeTokenUsage funnels post-execution token counts into the burn-rate
// tracker and cascades a predictive transition into the quota state store
// when the daily_token_budget is projected to be exceeded.
//
// Either argument may be nil; this is a no-op in that case. Provider names
// or non-positive token counts are likewise no-ops (apart from window
// initialization).
func (s *service) observeTokenUsage(provider string, tokens int, now time.Time) {
	if s == nil {
		return
	}
	quota.ObserveTokenUsage(s.providerBurnRate.innerTracker(), s.providerQuota.innerStore(), provider, tokens, now)
}

func (t *ProviderBurnRateTracker) innerTracker() *quota.BurnRateTracker {
	if t == nil {
		return nil
	}
	return t.inner
}

